// Decoded header (first segment)
{
  "alg": "RS256",
  "typ": "JWT",
  "kid": "2024-rotation-key-7"
}

// Decoded payload / claims (second segment)
{
  "iss": "https://as.example.com",
  "sub": "user-8a31f0",
  "aud": "https://api.example.com",
  "exp": 1893456000,
  "nbf": 1893455700,
  "iat": 1893455700,
  "jti": "f1d2c3b4-aaaa-bbbb-cccc-ddddeeeeffff",
  "scope": "api.read api.write",
  "roles": ["editor"]
}

// Server-side validation with Nimbus JOSE + JWT. Algorithm is PINNED to
// RS256 and keys are sourced from the AS's JWKS — both critical defenses.
import com.nimbusds.jose.JWSAlgorithm;
import com.nimbusds.jose.jwk.source.*;
import com.nimbusds.jose.proc.*;
import com.nimbusds.jwt.*;
import com.nimbusds.jwt.proc.*;
import java.net.URL;
import java.util.Set;

public final class TokenValidator {
  private final ConfigurableJWTProcessor<SecurityContext> processor;
  private static final String ISSUER = "https://as.example.com";
  private static final String AUDIENCE = "https://api.example.com";

  public TokenValidator(URL jwksUri) throws Exception {
    JWKSource<SecurityContext> keys =
        JWKSourceBuilder.create(jwksUri).build(); // caches + handles rotation
    var p = new DefaultJWTProcessor<SecurityContext>();
    // PIN RS256 only. This single line defeats alg:none and HS256 confusion.
    p.setJWSKeySelector(
        new JWSVerificationKeySelector<>(JWSAlgorithm.RS256, keys));
    p.setJWTClaimsSetVerifier(new DefaultJWTClaimsVerifier<>(
        AUDIENCE,                                 // require exact aud
        new JWTClaimsSet.Builder().issuer(ISSUER).build(), // require exact iss
        Set.of("sub", "exp", "iat")));            // require these claims exist
    this.processor = p;
  }

  /** Returns verified claims or throws if any check fails (exp/nbf included). */
  public JWTClaimsSet validate(String bearer) throws Exception {
    return processor.process(bearer, null); // verifies sig, iss, aud, exp, nbf
  }
}

// The alg:none attack token — header claims no signature is needed.
// A correct validator pinned to RS256 rejects this outright.
{
  "alg": "none",
  "typ": "JWT"
}
// ...followed by an attacker-chosen payload and an EMPTY signature segment:
