import { createRemoteJWKSet, jwtVerify, JWTPayload } from 'jose';

const ISSUER = 'https://as.example.com';
const AUDIENCE = 'https://api.example.com';

// Remote JWKS with built-in caching, cooldown, and key rotation support.
const JWKS = createRemoteJWKSet(
  new URL('https://as.example.com/.well-known/jwks.json'),
);

export async function validateAccessToken(token: string): Promise<JWTPayload> {
  const { payload, protectedHeader } = await jwtVerify(token, JWKS, {
    // PIN RS256: this rejects alg:none AND the HS256 key-confusion attack,
    // because the library refuses any algorithm not in this allowlist.
    algorithms: ['RS256'],
    issuer: ISSUER,      // enforces exact iss match
    audience: AUDIENCE,  // enforces this API is in aud
    // exp and nbf are validated automatically; add leeway for clock skew:
    clockTolerance: '30s',
  });

  // Defense in depth: assert the resolved header algorithm one more time.
  if (protectedHeader.alg !== 'RS256') {
    throw new Error('Unexpected signing algorithm: ' + protectedHeader.alg);
  }
  if (!payload.sub) {
    throw new Error('Token missing required sub claim');
  }
  return payload; // safe to use sub, scope, roles for authorization now
}

// Example usage in middleware:
export async function requireAuth(authHeader?: string): Promise<JWTPayload> {
  if (!authHeader?.startsWith('Bearer ')) {
    throw new Error('Missing or malformed Authorization header');
  }
  const token = authHeader.slice('Bearer '.length).trim();
  return validateAccessToken(token); // throws on any failed check
}

// Browser / Web Crypto implementation of RFC 7636 PKCE (S256).

function base64UrlEncode(bytes: Uint8Array): string {
  let binary = '';
  for (const b of bytes) binary += String.fromCharCode(b);
  return btoa(binary)
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/, '');
}

/** Generate a high-entropy code_verifier (RFC 7636: 43-128 chars). */
export function generateCodeVerifier(): string {
  const random = new Uint8Array(32);          // 32 bytes -> 43 base64url chars
  crypto.getRandomValues(random);             // cryptographically secure
  return base64UrlEncode(random);             // unreserved char set, no padding
}

/** Derive code_challenge = BASE64URL(SHA256(code_verifier)). */
export async function generateCodeChallenge(verifier: string): Promise<string> {
  const data = new TextEncoder().encode(verifier);
  const digest = await crypto.subtle.digest('SHA-256', data); // raw 32 bytes
  return base64UrlEncode(new Uint8Array(digest));
}

export async function createPkcePair() {
  const codeVerifier = generateCodeVerifier();
  const codeChallenge = await generateCodeChallenge(codeVerifier);
  return {
    codeVerifier,                 // keep secret in memory; send at /token
    codeChallenge,                // send on /authorize
    codeChallengeMethod: 'S256',  // never 'plain'
  };
}

// Usage: store codeVerifier (e.g. in sessionStorage tied to the flow), put
// codeChallenge + S256 on the /authorize request, then send codeVerifier
// (and NOT the challenge) on the /token exchange.
